public class AppointmentService
{
    private readonly ApplicationDbContext _db;

    public AppointmentService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Appointment>> GetAllAsync()
    {
        return await _db.Appointments
            .Include(a => a.Pet)
            .OrderByDescending(a => a.DateTime)
            .ToListAsync();
    }

    public async Task<Appointment?> GetByIdAsync(int id)
    {
        return await _db.Appointments
            .Include(a => a.Pet)
            .FirstOrDefaultAsync(a => a.Id == id);
    }

    public async Task<List<Appointment>> GetByDateRangeAsync(DateTime start, DateTime end)
    {
        return await _db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.DateTime >= start && a.DateTime < end)
            .OrderBy(a => a.DateTime)
            .ToListAsync();
    }

    public async Task<List<TimeOnly>> GetAvailableSlotsAsync(DateOnly date)
    {
        var startOfDay = date.ToDateTime(new TimeOnly(8, 0));
        var endOfDay = date.ToDateTime(new TimeOnly(18, 0));

        var bookedSlots = await _db.Appointments
            .Where(a => a.DateTime >= startOfDay && a.DateTime < endOfDay && a.Status != AppointmentStatus.Cancelled)
            .Select(a => a.DateTime)
            .ToListAsync();

        var available = new List<TimeOnly>();
        for (var time = new TimeOnly(8, 0); time < new TimeOnly(18, 0); time = time.AddMinutes(30))
        {
            var slotDateTime = date.ToDateTime(time);
            if (!bookedSlots.Contains(slotDateTime))
            {
                available.Add(time);
            }
        }

        return available;
    }

    public async Task<Appointment> CreateAsync(Appointment appointment)
    {
        appointment.CreatedAt = DateTime.UtcNow;
        _db.Appointments.Add(appointment);
        await _db.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAsync(Appointment appointment)
    {
        _db.Appointments.Update(appointment);
        await _db.SaveChangesAsync();
    }

    public async Task RescheduleAsync(int id, DateTime newDateTime)
    {
        var appointment = await _db.Appointments.FindAsync(id);
        if (appointment != null)
        {
            appointment.DateTime = newDateTime;
            await _db.SaveChangesAsync();
        }
    }

    public async Task CancelAsync(int id)
    {
        var appointment = await _db.Appointments.FindAsync(id);
        if (appointment != null)
        {
            appointment.Status = AppointmentStatus.Cancelled;
            await _db.SaveChangesAsync();
        }
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;

namespace VetClinic.Services;

public class BillingService
{
    private readonly ApplicationDbContext _db;

    public BillingService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Invoice>> GetInvoicesAsync(InvoiceStatus? statusFilter = null)
    {
        var query = _db.Invoices.Include(i => i.Pet).AsQueryable();
        if (statusFilter.HasValue)
        {
            query = query.Where(i => i.Status == statusFilter.Value);
        }
        return await query.OrderByDescending(i => i.InvoiceDate).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceByIdAsync(int id)
    {
        return await _db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.Payments.OrderByDescending(p => p.PaymentDate))
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        invoice.CreatedAt = DateTime.UtcNow;
        _db.Invoices.Add(invoice);
        await _db.SaveChangesAsync();
        return invoice;
    }

    public async Task<Payment> RecordPaymentAsync(Payment payment)
    {
        payment.CreatedAt = DateTime.UtcNow;
        _db.Payments.Add(payment);

        var invoice = await _db.Invoices.Include(i => i.Payments).FirstOrDefaultAsync(i => i.Id == payment.InvoiceId);
        if (invoice != null)
        {
            var totalPaid = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
            if (totalPaid >= invoice.TotalAmount)
            {
                invoice.Status = InvoiceStatus.Paid;
            }
        }

        await _db.SaveChangesAsync();
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int invoiceId)
    {
        return await _db.Payments
            .Where(p => p.InvoiceId == invoiceId)
            .OrderByDescending(p => p.PaymentDate)
            .ToListAsync();
    }

    public async Task<List<Treatment>> GetUnbilledTreatmentsAsync(int petId)
    {
        return await _db.Treatments
            .Where(t => t.PetId == petId)
            .OrderByDescending(t => t.Date)
            .ToListAsync();
    }

    public async Task<int> GetPendingInvoiceCountAsync()
    {
        return await _db.Invoices.CountAsync(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.Overdue);
    }
}

