@page "/"
@attribute [Authorize]

@inject PatientService PatientService
@inject AppointmentService AppointmentService
@inject BillingService BillingService

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments.Count</p>
                <a href="appointments" class="btn btn-primary btn-sm">View All</a>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
                <a href="billing" class="btn btn-primary btn-sm">View All</a>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Recent Patients</h5>
                <p class="card-text display-6">@recentPatients.Count</p>
                <a href="patients" class="btn btn-primary btn-sm">View All</a>
            </div>
        </div>
    </div>
</div>

<div class="row mt-4">
    <div class="col-md-6">
        <h4>Today's Schedule</h4>
        @if (todayAppointments.Any())
        {
            <table class="table table-sm">
                <thead><tr><th>Time</th><th>Pet</th><th>Reason</th><th>Status</th></tr></thead>
                <tbody>
                    @foreach (var apt in todayAppointments)
                    {
                        <tr>
                            <td>@apt.DateTime.ToString("HH:mm")</td>
                            <td>@apt.Pet.Name</td>
                            <td>@apt.Reason</td>
                            <td><span class="badge bg-@GetStatusColor(apt.Status)">@apt.Status</span></td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No appointments today.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Recent Patients</h4>
        @if (recentPatients.Any())
        {
            <table class="table table-sm">
                <thead><tr><th>Name</th><th>Species</th><th>Owner</th></tr></thead>
                <tbody>
                    @foreach (var pet in recentPatients)
                    {
                        <tr>
                            <td><a href="patients/@pet.Id">@pet.Name</a></td>
                            <td>@pet.Species</td>
                            <td>@pet.OwnerName</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
