@page "/appointments"
@attribute [Authorize]

@inject AppointmentService AppointmentService

<PageTitle>Appointments - VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Appointments</h1>
    <a href="appointments/create" class="btn btn-primary">New Appointment</a>
</div>

<div class="mb-3">
    <div class="btn-group">
        <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&lt; Previous</button>
        <button class="btn btn-outline-secondary" disabled>@weekStart.ToString("MMM d") - @weekStart.AddDays(6).ToString("MMM d, yyyy")</button>
        <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &gt;</button>
    </div>
    <button class="btn btn-outline-primary ms-2" @onclick="GoToToday">Today</button>
</div>

<div class="table-responsive">
    <table class="table table-bordered">
        <thead>
            <tr>
                <th style="width:80px">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="@(day == DateTime.Today ? "table-active" : "")">@day.ToString("ddd M/d")</th>
                }
            </tr>
        </thead>
        <tbody>
            @for (var time = new TimeOnly(8, 0); time < new TimeOnly(18, 0); time = time.AddMinutes(30))
            {
                <tr>
                    <td class="text-muted small">@time.ToString("HH:mm")</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var slotTime = weekStart.AddDays(d).Add(time.ToTimeSpan());
                        var apt = appointments.FirstOrDefault(a => a.DateTime == slotTime);
                        if (apt != null)
                        {
                            <td class="bg-@GetStatusColor(apt.Status) bg-opacity-25 small">
                                <a href="appointments/@apt.Id">@apt.Pet.Name - @apt.Reason</a>
                            </td>
                        }
                        else
                        {
                            <td></td>
                        }
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateTime weekStart;
    private List<Appointment> appointments = new();

    protected override async Task OnInitializedAsync()
    {
        weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek + (int)DayOfWeek.Monday);
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        appointments = await AppointmentService.GetByDateRangeAsync(weekStart, weekStart.AddDays(7));
    }

    private async Task PreviousWeek()
    {
        weekStart = weekStart.AddDays(-7);
        await LoadAppointments();
    }

    private async Task NextWeek()
    {
        weekStart = weekStart.AddDays(7);
        await LoadAppointments();
    }

    private async Task GoToToday()
    {
        weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek + (int)DayOfWeek.Monday);
        await LoadAppointments();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        _ => "info"
    };
}

