@code {
    [SupplyParameterFromForm]
    private Invoice invoice { get; set; } = new();

    private List<Pet>? pets;
    private List<Treatment>? treatments;
    private HashSet<int> selectedTreatments = new();
    private DateOnly invoiceDate = DateOnly.FromDateTime(DateTime.Today);
    private DateOnly dueDate = DateOnly.FromDateTime(DateTime.Today.AddDays(30));

    protected override async Task OnInitializedAsync()
    {
        pets = await PatientService.GetAllAsync();
    }

    private async Task LoadTreatments()
    {
        if (invoice.PetId > 0)
        {
            treatments = await BillingService.GetUnbilledTreatmentsAsync(invoice.PetId);
            selectedTreatments.Clear();
            invoice.TotalAmount = 0;
        }
    }

    private void ToggleTreatment(int treatmentId, bool selected)
    {
        if (selected)
            selectedTreatments.Add(treatmentId);
        else
            selectedTreatments.Remove(treatmentId);

        if (treatments != null)
        {
            invoice.TotalAmount = treatments.Where(t => selectedTreatments.Contains(t.Id)).Sum(t => t.Cost);
        }
    }

    private async Task HandleSubmit()
    {
        invoice.InvoiceDate = invoiceDate.ToDateTime(TimeOnly.MinValue);
        invoice.DueDate = dueDate.ToDateTime(TimeOnly.MinValue);
        await BillingService.CreateInvoiceAsync(invoice);
        Navigation.NavigateTo("billing");
    }
}

