    private Payment newPayment = new();
    private decimal totalPaid;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        invoice = await BillingService.GetInvoiceByIdAsync(Id);
        if (invoice != null)
        {
            totalPaid = invoice.Payments.Sum(p => p.Amount);
            newPayment.Amount = invoice.TotalAmount - totalPaid;
        }
    }

    private async Task RecordPayment()
    {
        newPayment.InvoiceId = Id;
        newPayment.PaymentDate = DateTime.UtcNow;
        await BillingService.RecordPaymentAsync(newPayment);
        newPayment = new Payment();
        await LoadInvoice();
    }

    private string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Overdue => "danger",
        _ => "info"
    };
}

