@page "/billing/create"
@attribute [Authorize]

@inject BillingService BillingService
@inject PatientService PatientService
@inject NavigationManager Navigation

<PageTitle>Create Invoice - VetClinic</PageTitle>

<h1>Create Invoice</h1>

<div class="row">
    <div class="col-md-8">
        <EditForm Model="invoice" OnValidSubmit="HandleSubmit" FormName="createInvoice">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label class="form-label">Pet</label>
                <InputSelect class="form-select" @bind-Value="invoice.PetId" @bind-Value:after="LoadTreatments">
                    <option value="0">-- Select Pet --</option>
                    @if (pets != null)
                    {
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.OwnerName)</option>
                        }
                    }
                </InputSelect>
            </div>

            @if (treatments != null && treatments.Any())
            {
                <div class="mb-3">
                    <label class="form-label">Treatments to Include</label>
                    <div class="list-group">
                        @foreach (var t in treatments)
                        {
                            <label class="list-group-item">
                                <input type="checkbox" class="form-check-input me-2"
                                       checked="@selectedTreatments.Contains(t.Id)"
                                       @onchange="(e) => ToggleTreatment(t.Id, (bool)(e.Value ?? false))" />
                                @t.Date.ToString("yyyy-MM-dd") - @t.Description — @t.Cost.ToString("C")
                            </label>
                        }
                    </div>
                </div>
            }

            <div class="row mb-3">
                <div class="col-md-6">
                    <label class="form-label">Invoice Date</label>
                    <InputDate class="form-control" @bind-Value="invoiceDate" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Due Date</label>
                    <InputDate class="form-control" @bind-Value="dueDate" />
                </div>
            </div>

            <div class="mb-3">
                <label class="form-label">Total Amount</label>
                <InputNumber class="form-control" @bind-Value="invoice.TotalAmount" />
            </div>

            <div class="mb-3">
                <label class="form-label">Notes</label>
                <InputTextArea class="form-control" @bind-Value="invoice.Notes" rows="3" />
            </div>

            <button type="submit" class="btn btn-primary">Create Invoice</button>
            <a href="billing" class="btn btn-secondary ms-2">Cancel</a>
        </EditForm>
    </div>
</div>

@code {
    [SupplyParameterFromForm]
    private Invoice invoice { get; set; } = new();

    private List<Pet>? pets;
    private List<Treatment>? treatments;
    private HashSet<int> selectedTreatments = new();
    private DateOnly invoiceDate = DateOnly.FromDateTime(DateTime.Today);
    private DateOnly dueDate = DateOnly.FromDateTime(DateTime.Today.AddDays(30));

    protected override async Task OnInitializedAsync()
    {
        pets = await PatientService.GetAllAsync();
    }

    private async Task LoadTreatments()
    {
        if (invoice.PetId > 0)
        {
            treatments = await BillingService.GetUnbilledTreatmentsAsync(invoice.PetId);
            selectedTreatments.Clear();
            invoice.TotalAmount = 0;
        }
    }

    private void ToggleTreatment(int treatmentId, bool selected)
    {
        if (selected)
            selectedTreatments.Add(treatmentId);
        else
            selectedTreatments.Remove(treatmentId);

        if (treatments != null)
        {
            invoice.TotalAmount = treatments.Where(t => selectedTreatments.Contains(t.Id)).Sum(t => t.Cost);
        }
    }

    private async Task HandleSubmit()
    {
        invoice.InvoiceDate = invoiceDate.ToDateTime(TimeOnly.MinValue);
        invoice.DueDate = dueDate.ToDateTime(TimeOnly.MinValue);
        await BillingService.CreateInvoiceAsync(invoice);
        Navigation.NavigateTo("billing");
    }
}

